class Solution:
    def maximumLength(self, s: str) -> int:
        runs = defaultdict(list)
        n = len(s)
        i = 0
        while i < n:
            c = s[i]
            j = i
            while j < n and s[j] == c:
                j += 1
            runs[c].append(j - i)
            i = j

        max_len = -1
        for c in runs:
            lengths = runs[c]
            lengths.sort(reverse=True)
            for L in range(min(lengths), 0, -1):
                cnt = 0
                for run in lengths:
                    cnt += max(0, run - L + 1)
                    if cnt >= 3:
                        max_len = max(max_len, L)
                        break
                if cnt >= 3:
                    break
        return max_len

